cd ~/.claude && node -e "
const fs = require('fs');

const settings = JSON.parse(fs.readFileSync('settings.json', 'utf8'));

if (!settings.hooks) settings.hooks = {};

const hookCommand = 'git -C ~/.claude pull --no-rebase --autostash --quiet 2>/dev/null || (cd ~/.claude && git checkout --ours . && git add -A && git commit -m \"sync: auto-resolve\" --quiet) 2>/dev/null || true';

const sessionStartHooks = settings.hooks.SessionStart || [];

let hasCcSync = false;
for (const hookGroup of sessionStartHooks) {
  for (const hook of (hookGroup.hooks || [])) {
    if (hook.command && hook.command.includes('git -C ~/.claude pull')) {
      hasCcSync = true;
      break;
    }
  }
}

if (!hasCcSync) {
  sessionStartHooks.push({
    hooks: [{
      type: 'command',
      command: hookCommand
    }]
  });
  settings.hooks.SessionStart = sessionStartHooks;
}

fs.writeFileSync('settings.json', JSON.stringify(settings, null, 2) + '\n');
console.log('OK');
"
